void newGame({bool useSaveFile = true}) async {
    try {
      if (!useSaveFile) throw 'not using save';

      final File saveFile = await _saveFile;

      if (!saveFile.existsSync()) throw 'savefile does not exist';

      final pbGame = PbGame.fromBuffer(saveFile.readAsBytesSync());

      _bank.imbueDataBank(pbGame.bank);
      _afk.imbueDataAfk(pbGame.afk);
      _clicker.imbueDataClicker(pbGame.clicker);

      _setupMultimerchUpgradeList();
    }

    // on any savefile-related exeptions
    catch (_) {
      //print("$_, resetting game");
      resetGame();
    }

    _timer = Timer.periodic(
      const Duration(milliseconds: 1000 ~/ Tick.tickRate),
      (timer) {
        instance._afk.tick();
      },
    );
  }

here is a constructor for afk to clarify: factory Afk.create(
    Bank bank,
    MultimerchBehavior multimerchBehavior,
  ) {
    final afk = Afk._(bank);

    afk.createHiddenParent();

    afk._afkMultiplier = AfkMultiplier.create(afk);

    afk._enterprises = List.generate(
      EnterpriseData.enterprisesImplemented,
      (index) => Enterprise.create(
        afk,
        bank,
        index,
        multimerchBehavior,
      ),
    );

    afk._offlineEarner = AfkOfflineEarner.create();

    return afk;
  }

Here is the constructor of enterprise: factory Enterprise.create(
    Afk? afk,
    Bank bank,
    int index,
    MultimerchBehavior multimerchBehavior,
  ) {
    final e = Enterprise._(afk, bank, index);

    e.createCanBeHidden(afk);
    e.createHiddenParent();

    e.multimerch = Multimerch(e, multimerchBehavior);

    e.tierUpgrades = List.generate(
      EnterpriseTierUpgrade.implemented,
      (index) => EnterpriseTierUpgrade.create(e, index),
      growable: false,
    );

    e.quantityMilestones = List.generate(
      EnterpriseQuantityMilestone.implemented,
      (index) => EnterpriseQuantityMilestone.create(e, index),
      growable: false,
    );

    return e;
  }

void imbueDataEnterprise(PbEnterprise pb) {
    multimerch.imbueProtobuf(pb.multimerch);

    _investedInEnterprise = pb.investedInEnterprise;
    _earnedByEnterprise = pb.earnedByEnterprise;

    for (final u in tierUpgrades) {
      u.imbueDataUpgrade(pb.enterpriseTierUpgrades.upgrades[u.upgradeIndex]);
    }

    // RECALCULATES

    _performRecalculations();
  }

  void _performRecalculations() {
    recalculateCostPerUnit();
    // recalculateCostNext() is also called

    recalculateCumulativePricetag();

    determineHiddens();

    recalculateTier();

    reachQuantityMilestones();

    // recalculateIncomePerUnit()
    // is called from recalculateTier
    // and Afk.recalculateAfkMultiplier
  }
